+ALTER PROCEDURE dbo.s_enc_delete_SubContractCOPCOItemLinks
+  @PCOItemID                    int ,
+  @ItemNumber                   nvarchar(30) ,
+  @PCOID                        int ,
+  @ChangeOrderID                int ,
+  @SCONumber                    nvarchar(30) ,
+  @ContractID                   int ,
+  @CostAllocationCode           int ,
+  @CostAppliedAmount            money ,
+  @ProjectID                    int ,
+  @WhenRequested                datetimeoffset ,
+  @RequestedBy                  nvarchar(255) ,
+  @RequestedByContactID         int ,
+  @RequestedByUserID            uniqueidentifier , -- wrong order
+  @ValidationErrorCode          int = 0 OUTPUT
+AS
+DECLARE
+  @PrevCostAllocationCode INT,
+  @PrevIsLockedBySCO BIT
+
+  SET XACT_ABORT ON
+  SET NOCOUNT ON
+
+    /* Bail if the item is no longer associated with a change order */
+  IF ISNULL(@ChangeOrderID, 0) = 0
+    RETURN
+
+    /* Ensure this item has not been invoiced */
+  IF EXISTS(SELECT 1
+              FROM ContractInvoiceItems
+             WHERE PCOItemID = @PCOItemID
+               AND Deleted = 0)
+    BEGIN
+      SET @ValidationErrorCode = -1006
+      RETURN
+    END
+
+  UPDATE PotentialCOItems
+     SET @PrevCostAllocationCode          = CostAllocationCode ,
+         @PrevIsLockedBySCO               = IsLockedBySCO ,
+
+         ChangeOrderID                    = NULL ,
+         CostAllocationCode               = @CostAllocationCode ,
+         IsLockedBySCO                    = 0 ,
+         LastModified                     = @WhenRequested ,
+         LastModifiedBy                   = @RequestedBy ,
+         LastModifiedByUserID             = @RequestedByUserID
+   WHERE PCOItemID = @PCOItemID
+     AND Deleted = 0
+
+DECLARE
+  @Reason       INT
+
+  SELECT @Reason = Value
+    FROM SQLEnums
+   WHERE Category = 1
+     AND Identifier = 'PCO_PCOItemRemovedFromSCO'
+
+  INSERT
+    INTO History (
+         TableType ,
+         ProjectID ,
+         RecordId ,
+         Guid,
+         DataReadable ,
+         LastModified,
+         LastModifiedBy ,
+         LastModifiedByUserID ,
+         LastModifiedByContactID ,
+         Reason,
+         ReasonIdentifier1,
+         ReasonIdentifier2)
+  SELECT 1 /* PrologTable.Types.PotentialCO */ ,
+         @ProjectID ,
+         i.PCOID,
+         p.GUID ,
+         (SELECT TableType = CAST(2 AS INT) /* PrologTable.Types.PotentialCOItem */,
+                 RecordID = i.PCOItemID ,
+                 p.GUID ,
+                 Description = i.ItemNumber + ' - ' + i.Description ,
+                 (SELECT * FROM
+                  (SELECT Name = CAST('ChangeOrderID' AS NVARCHAR(100)),
+                          NewValue = NULL ,
+                          OldValue = CAST(@ChangeOrderID AS nvarchar(max))
+                   UNION
+                   SELECT Name = CAST('SCONumber' AS NVARCHAR(100)),
+                          NewValue = NULL ,
+                          OldValue = @SCONumber
+                   UNION
+                   SELECT Name = CAST('CostAllocationCode' AS NVARCHAR(100)),
+                          NewValue = CAST(@CostAllocationCode AS nvarchar(max)) ,
+                          OldValue = CAST(@PrevCostAllocationCode AS nvarchar(max))
+                   UNION
+                   SELECT Name = CAST('IsLockedBySCO' AS NVARCHAR(100)),
+                          NewValue = '0' ,
+                          OldValue = CAST(@PrevIsLockedBySCO AS nvarchar(max))
+                   ) AS a FOR XML RAW, TYPE
+                  ) AS FieldChanges
+           FOR XML RAW),
+          @WhenRequested,
+          @RequestedBy ,
+          @RequestedByUserID ,
+          @RequestedByContactID,
+          @Reason,
+          @SCONumber,
+          @ItemNumber
+     FROM PotentialCOItems i INNER JOIN PotentialCO p ON i.PCOID = p.PCOID
+    WHERE i.PCOItemID = @PCOItemID
+
+  IF @CostAppliedAmount <> 0
+    BEGIN
+      DECLARE
+        @PotentialValue    money ,
+        @PotentialChangeValue money ,
+        @ItemKey           nvarchar(100) ,
+        @HistoryEntry      NVARCHAR(MAX) ,
+        @ModifiedRecords   ProjectIDRecordIDGUIDTableType
+
+      UPDATE Contracts
+         SET @PotentialValue      = PotentialValue ,
+             PotentialValue       = PotentialValue - @CostAppliedAmount ,
+             @PotentialChangeValue= PotentialChangeValue,
+             PotentialChangeValue = PotentialChangeValue + @CostAppliedAmount,
+             LastModified         = @WhenRequested ,
+             LastModifiedBy       = @RequestedBy ,
+             LastModifiedByUserID = @RequestedByUserID
+      OUTPUT INSERTED.ProjectID ,
+             INSERTED.ContractID,
+             INSERTED.GUID
+             INTO @ModifiedRecords
+       WHERE ContractID = @ContractID
+         AND Deleted = 0;
+
+         WITH HistoryEntries AS
+                    (SELECT Name = CAST('PotentialChangeValue' AS NVARCHAR(100)),
+                            NewValue = @PotentialChangeValue + @CostAppliedAmount ,
+                            OldValue = @PotentialChangeValue
+
+                     UNION
+
+                     SELECT Name = CAST('PotentialValue' AS NVARCHAR(100)),
+                            NewValue = @PotentialValue - @CostAppliedAmount ,
+                            OldValue = @PotentialValue)
+         SELECT @HistoryEntry = (SELECT * FROM HistoryEntries FOR XML RAW)
+
+      SELECT @ItemKey = PCONumber + '-' + @ItemNumber
+        FROM PotentialCO
+       WHERE PCOID = @PCOID
+
+      EXEC s_enc_add_history_for_modified_records 5 /* PrologTable.Types.Contract */, @HistoryEntry, @ModifiedRecords, @WhenRequested, @RequestedBy, @RequestedByContactID, @RequestedByUserID, 'Contract_PCOItemRemovedFromSCO', @SCONumber, @ItemKey
+    END
+GO
